import React, { Component } from 'react';
import { useMediaQuery } from 'react-responsive'
import Iframe from 'react-iframe'


const Desktop = ({ children }) => {
    const isDesktop = useMediaQuery({ minWidth: 992 })
    return isDesktop ? children : null
  }
  const Tablet = ({ children }) => {
    const isTablet = useMediaQuery({ minWidth: 768, maxWidth: 991 })
    return isTablet ? children : null
  }
  const Mobile = ({ children }) => {
    const isMobile = useMediaQuery({ maxWidth: 767 })
    return isMobile ? children : null
  }
  const Default = ({ children }) => {
    const isNotMobile = useMediaQuery({ minWidth: 768 })
    return isNotMobile ? children : null
  }



class responsive extends Component {

   constructor() {
      super();
      var today = new Date();
      this.state = { screen : 0, url: ""};

      //this.handleSubmit = this.handleSubmit.bind(this);
    }





    componentWillMount() {

    }

    handleSetLink = (url) => {

        this.setState({url: url})
        this.setState({screen: 1})
      }


      handleBack = () => {
        this.setState({screen: 0})
      }






   render() {

    var showDiv = "";




    try {
        /*
      Array.from(new Set(this.state.uploadResponse.map(groups => groups.date))).map(group => {return {date: group}}).map(Record =>(
        this.inputArrayData(Record.date, items)
        //console.dir(Record)
      ))*/
      if (this.state.screen == 0) {
        showDiv = <div>
            <div style={{margin: "0px", width: "100%", backgroundColor: "#052049", color: "#fff", padding: "10px"}}>UCSF University of California San Francisco</div>


            <div style={{marginTop: "20px", width: "100%", alignItems: "center", justifyContent: "center", display: "flex", fontSize: "25px"}}>UCSF Workflow Activation</div>

            <div style={{marginTop: "30px", width: "100%", alignItems: "center", justifyContent: "center", display: "flex"}}><button style={{width: "60%", height: "50px", textDecoration: "none", backgroundColor: "#052049", color: "#fff"}} onClick={() => {this.handleSetLink("https://mcconxvip001.ucsfmedicalcenter.org/files/dhb/index.html?authentication=AG0SN7tHstvh0uE2gD8jZF6qIznihmjwHkWhF3841X0A-UrySNhSN7zAl4nLaExh")}}>Parnassus</button></div>

            <div style={{marginTop: "20px", width: "100%", alignItems: "center", justifyContent: "center", display: "flex"}}><button style={{width: "60%", height: "50px", textDecoration: "none", backgroundColor: "#052049", color: "#fff"}} onClick={() => {this.handleSetLink("https://mcconxvip001.ucsfmedicalcenter.org/files/dhb/index.html?authentication=bOfEx2QPJoYDBUIJV9ikwF7MyY8JFVbmJN1DjfGhGJQ5uymeaONpBuj0Gbo_KPVP")}}>Mission Bay</button></div>

            <div style={{marginTop: "20px", width: "100%", alignItems: "center", justifyContent: "center", display: "flex"}}><button style={{width: "60%", height: "50px", textDecoration: "none", backgroundColor: "#052049", color: "#fff"}} onClick={() => {this.handleSetLink("https://mcconxvip001.ucsfmedicalcenter.org/files/dhb/index.html?authentication=zjIvBE1zVv3W_7vlluN7rpMN5Q8Se-pb0OkWx1_Q16kouLCXtp4rGv4OjfV8890e")}}>Mount Zion</button></div>



            </div>

      }

      if (this.state.screen == 1) {
        showDiv = <div>
        <Mobile>
            <div style={{marginTop: "10px", marginBottom: "20px"}}><button style={{padding: "0", border: "none", background: "none"}} onClick={() => {this.handleBack()}}>Back</button></div>
                <Iframe url={this.state.url}
            width="100%"
            height="800px"
            id=""
            className=""
            display="block"
            position="relative"/>

        </Mobile>
        <Default>
            <div style={{marginTop: "10px", marginBottom: "20px"}}><button style={{padding: "0", border: "none", background: "none"}} onClick={() => {this.handleBack()}}>Back</button></div>
                <Iframe url={this.state.url}
            width="100%"
            height="800px"
            id=""
            className=""
            display="block"
            position="relative"/>

        </Default>
        </div>
      }

    } catch (e) {
      showDiv = "You don't have permission for using this application!"
    }




      return (
        <div style={{minHeight: "500px", marginLeft: "0px", marginRight: "0px"}}>{showDiv}</div>
       )
   }
 }

 //<div><pre>{JSON.stringify(this.state.uploadResponse, null, 2) }</pre></div>

 export default responsive;
